import{_ as a,o as n,c as s,a2 as t}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Chapter 7: Process Management and Shell","description":"Understanding the Unix process model and how to safely spawn, manage, and sandbox child processes from Rust.","frontmatter":{"title":"Chapter 7: Process Management and Shell","description":"Understanding the Unix process model and how to safely spawn, manage, and sandbox child processes from Rust."},"headers":[],"relativePath":"learn/linear/07-process-management-and-shell/index.md","filePath":"learn/linear/07-process-management-and-shell/index.md"}'),r={name:"learn/linear/07-process-management-and-shell/index.md"};function i(l,e,o,d,c,h){return n(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="process-management-and-shell" tabindex="-1">Process Management and Shell <a class="header-anchor" href="#process-management-and-shell" aria-label="Permalink to &quot;Process Management and Shell&quot;">​</a></h1><p>This chapter dives deep into the Unix process model and how it underpins everything a coding agent does when it executes external commands. You will learn how processes are created via fork/exec, how file descriptors connect parent and child through stdin/stdout/stderr pipes, and how signals provide the mechanism for timeouts and graceful shutdown. These fundamentals are essential for building an agent that runs shell commands, compilers, test suites, and other tools on behalf of the user.</p><p>Beyond the basics, we explore the critical security dimension of process execution. A coding agent that runs arbitrary commands must enforce resource limits, sandbox dangerous operations, and validate inputs to prevent misuse. You will implement process spawning with configurable timeouts, environment isolation, and working directory control -- the same patterns used in production agent systems.</p><p>Finally, we tie these concepts together with parallel execution strategies. When an agent needs to run multiple tools concurrently -- say, a linter and a test suite -- you need patterns for managing process groups, collecting results, and handling partial failures gracefully.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Understand the Unix process lifecycle: fork, exec, wait, and exit</li><li>Spawn and manage child processes using Rust&#39;s std::process and tokio::process</li><li>Capture and stream stdout/stderr from child processes</li><li>Implement signal handling, timeouts, and graceful process termination</li><li>Apply sandboxing and resource limit techniques to constrain child processes</li><li>Execute multiple processes in parallel and aggregate their results</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/07-process-management-and-shell/01-unix-process-model.html">Unix Process Model</a></li><li><a href="/linear/07-process-management-and-shell/02-spawning-processes-in-rust.html">Spawning Processes in Rust</a></li><li><a href="/linear/07-process-management-and-shell/03-capturing-output.html">Capturing Output</a></li><li><a href="/linear/07-process-management-and-shell/04-stdin-stdout-stderr.html">Stdin Stdout Stderr</a></li><li><a href="/linear/07-process-management-and-shell/05-signals-and-timeouts.html">Signals and Timeouts</a></li><li><a href="/linear/07-process-management-and-shell/06-environment-and-working-dir.html">Environment and Working Dir</a></li><li><a href="/linear/07-process-management-and-shell/07-shell-vs-exec.html">Shell vs Exec</a></li><li><a href="/linear/07-process-management-and-shell/08-sandboxing-approaches.html">Sandboxing Approaches</a></li><li><a href="/linear/07-process-management-and-shell/09-resource-limits.html">Resource Limits</a></li><li><a href="/linear/07-process-management-and-shell/10-parallel-execution.html">Parallel Execution</a></li><li><a href="/linear/07-process-management-and-shell/11-security-hardening.html">Security Hardening</a></li><li><a href="/linear/07-process-management-and-shell/12-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 6 (file system operations for context on working with the filesystem that child processes will access)</li></ul>',10)])])}const u=a(r,[["render",i]]);export{p as __pageData,u as default};
